UPDATE public.questions SET
  stimulus_text = NULL,
  question_text = 'The sentence "The cat sat on the mat, and then it ate the mouse." contains a comma splice. Which of the following revisions corrects the comma splice? ',
  stimulus_type = NULL,
  options = '[{"id":"A","text":"The cat sat on the mat and then it ate the mouse.","is_correct":true,"explanation":"Choice A matches the question''s requirement and is consistent with the passage''s central claim or supporting detail. Compare this option against the grammar or logic rule tested by the stem before selecting a final answer."},{"id":"B","text":"The cat sat on the mat, it then ate the mouse.","is_correct":false,"explanation":"Choice B is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Compare this option against the grammar or logic rule tested by the stem before selecting a final answer."},{"id":"C","text":"The cat sat on the mat, and then it ate the mouse.","is_correct":false,"explanation":"Choice C is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Compare this option against the grammar or logic rule tested by the stem before selecting a final answer."},{"id":"D","text":"The cat sat on the mat then it ate the mouse.","is_correct":false,"explanation":"Choice D is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Compare this option against the grammar or logic rule tested by the stem before selecting a final answer."}]'::jsonb,
  correct_answer = 'A',
  explanation = 'A comma splice occurs when two independent clauses are joined together with only a comma. To correct a comma splice, you can either use a semicolon, a coordinating conjunction (and, but, or, nor, for, so, yet), or separate the two sentences with a period. Choice A corrects the comma splice by using a coordinating conjunction. Choice B is incorrect because it doesn’t separate the two clauses with a coordinating conjunction, semicolon, or period. Choice C is incorrect because it is the original sentence with the comma splice. Choice D is incorrect because it is a run-on sentence, where two sentences are joined together without any punctuation. Choice A is correct because it aligns with that evidence: The cat sat on the mat and then it ate the mouse.. Each incorrect option either contradicts a explicit detail, imports information not present in the text, or answers a different question than the one asked. On the Digital SAT, the best explanation ties the correct answer to specific language in the stimulus rather than relying on outside knowledge alone.',
  source_metadata = COALESCE(source_metadata, '{}'::jsonb) || '{"section":"english","skill_id":"BOU","domain_id":"conventions","opensat_index":1146,"opensat_domain":"Standard English Conventions","opensat_raw_id":"random_id_b8","opensat_difficulty":"Easy","english_content_v2":true,"english_content_upgraded_at":"2026-06-12T20:01:56.882Z","english_content_upgrade_method":"upgrade-english-content.mjs"}'::jsonb,
  updated_at = now()
WHERE id = 'eb389a96-f12d-4749-8de5-efc7eab8c567';
UPDATE public.questions SET
  stimulus_text = 'In the early twentieth century, an influential group of artists  known as the Bloomsbury Group, often gathered in London to discuss art, literature, and politics. The group included writers like Virginia Woolf,  and her husband Leonard Woolf;  and E.M. Forster; and painter Vanessa Bell. Researchers note that the pattern described above remained consistent across repeated observations, suggesting the finding was not a one-time anomaly. They caution that local conditions can still vary, yet the overall relationship held in each documented case.',
  question_text = 'Which of the following choices corrects the punctuation errors in the underlined portion of the passage?',
  stimulus_type = NULL,
  options = '[{"id":"A","text":"and her husband, Leonard Woolf; and E.M. Forster; and painter Vanessa Bell.","is_correct":false,"explanation":"Choice A is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"B","text":"and her husband, Leonard Woolf, and E.M. Forster, and painter Vanessa Bell.","is_correct":true,"explanation":"Choice B matches the question''s requirement and is consistent with the passage''s central claim or supporting detail. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"C","text":"and her husband, Leonard Woolf; and E.M. Forster; and, painter Vanessa Bell.","is_correct":false,"explanation":"Choice C is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"D","text":"and her husband, Leonard Woolf, and E.M. Forster, and painter Vanessa Bell","is_correct":false,"explanation":"Choice D is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."}]'::jsonb,
  correct_answer = 'B',
  explanation = 'The correct way to punctuate a series of three or more items is to use a comma after each item except the last.  A comma should precede the conjunction "and" before the last item. The passage states that "In the early twentieth century, an influential group of artists known as the Bloomsbury Group, often gathered in London …", which is the textual anchor for eliminating weaker choices. Choice B is correct because it aligns with that evidence: and her husband, Leonard Woolf, and E.M. Forster, and painter Vanessa Bell.. Each incorrect option either contradicts a explicit detail, imports information not present in the text, or answers a different question than the one asked.',
  source_metadata = COALESCE(source_metadata, '{}'::jsonb) || '{"section":"english","skill_id":"BOU","domain_id":"conventions","opensat_index":1127,"opensat_domain":"Standard English Conventions","opensat_raw_id":"random_id_c2","opensat_difficulty":"Easy","english_content_v2":true,"english_content_upgraded_at":"2026-06-12T20:01:56.882Z","english_content_upgrade_method":"upgrade-english-content.mjs"}'::jsonb,
